def valid(slot_start, slot_end, alice_events, bob_events, carol_events):
    day = slot_start.date()
    if not (datetime.time(9,0) <= slot_start.time() and slot_end.time() <= datetime.time(14,0)):
        return False
    if slot_start.time() < datetime.time(10,0):
        return False
    if day.weekday() in (1,3):
        if slot_end.time() > datetime.time(16,30):
            return False
    elif slot_end.time() > datetime.time(17,0):
        return False
    lunch_s = datetime.datetime.combine(day, datetime.time(12,0))
    lunch_e = datetime.datetime.combine(day, datetime.time(12,30))
    if slot_start < lunch_e and slot_end > lunch_s:
        return False
    for events in (alice_events, bob_events, carol_events):
        for e_start, e_end in events:
            if slot_start < e_end and slot_end > e_start:
                return False
    return True

